import numpy as np

# Common backbone idea: Use heuristic scoring combining distance, time window constraints, and urgency to decide next customer node.

# {Use reinforcement learning-inspired Q-value estimation to find future benefit of visiting nodes based on distance, time window, urgency, and expected future interactions.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def calculate_q_value(customer_pos, customer_index):
        distance = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + distance
        start_time, end_time = time_windows[customer_index]

        if arrival_time > end_time:
            return -float('inf')  # Missed time window

        # Calculate Q-value components
        immediate_reward = -distance  # Prefer closer nodes
        potential_future_benefit = 1 / ((end_time - current_time) + 1)  # Favor imminent time windows

        if arrival_time < start_time:
            waiting_penalty = start_time - arrival_time
        else:
            waiting_penalty = 0

        # Combine values to estimate Q-value
        q_value = immediate_reward - waiting_penalty + potential_future_benefit
        return q_value

    best_q_value = -float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        q_value = calculate_q_value(customer_pos, i)

        if q_value > best_q_value:
            best_q_value = q_value
            best_node = i

    return best_node
